 	{ "Cyrix 486S/DX",	CPUCLASS_486 },		/* CPU_CY486DX */
+	{ "AMD K5",		CPUCLASS_586 },		/* CPU_AMDK5 */
+	{ "AMD K6",		CPUCLASS_586 },		/* CPU_AMDK6 */
 };

